<?php

declare(strict_types=1);

namespace OCA\WikiJsDashboard\Dashboard;

use OCA\WikiJsDashboard\Service\WikiJsClient;
use OCP\Dashboard\IAPIWidgetV2;
use OCP\Dashboard\IWidget;
use OCP\Dashboard\IIconWidget;
use OCP\Dashboard\Model\WidgetItem;
use OCP\Dashboard\Model\WidgetItems;
use OCP\IL10N;
use OCP\IURLGenerator;
use OCP\Util;
use Psr\Log\LoggerInterface;

class WikiJsWidget implements IWidget, IAPIWidgetV2, IIconWidget {
	private IL10N $l10n;
	private IURLGenerator $urlGenerator;
	private WikiJsClient $client;
	private LoggerInterface $logger;

	/**
	 * Inline SVG icon (no external fetch).
	 * Kept small and monochrome; inherits currentColor.
	 */
	private const INLINE_ICON_DATA_URI = 'data:image/svg+xml;base64,';

	public function __construct(
		IL10N $l10n,
		IURLGenerator $urlGenerator,
		WikiJsClient $client,
		LoggerInterface $logger
	) {
		$this->l10n = $l10n;
		$this->urlGenerator = $urlGenerator;
		$this->client = $client;
		$this->logger = $logger;
	}

	public function getId(): string {
		return 'wikijs_dashboard';
	}

	public function getTitle(): string {
		return $this->l10n->t('Dokumentace NPŠ');
	}

	public function getOrder(): int {
		return 10;
	}

	public function getIconClass(): string {
		return 'icon-category-office';
	}

	public function getIconUrl(): string {
		// Prefer explicit icon URL for Dashboard API.
		return 'data:image/svg+xml;base64,';
	}

	public function getUrl(): ?string {
		// No global widget link; items have their own links.
		return null;
	}

	public function load(): void {
		// Rendered by Dashboard API; keep only CSS.
		Util::addStyle('wikijs_dashboard', 'dashboard');
	}

	/**
	 * Dashboard API v2/v3 (IAPIWidgetV2)
	 */
	public function getItemsV2(string $userId, ?string $since = null, int $limit = 7): WidgetItems {
		try {
			$changes = $this->client->getChanges($limit);

			$items = [];
			foreach ($changes as $c) {
				if (!is_array($c)) {
					continue;
				}

				$title = (string)($c['title'] ?? '');
				$link  = (string)($c['url'] ?? '');
				$updatedAt = (string)($c['updatedAt'] ?? '');

				if ($title === '' || $link === '') {
					continue;
				}

				$subtitle = $this->formatUpdatedAt($updatedAt);
				$sinceId = sha1($link);

				// Nextcloud 32: WidgetItem constructor is:
				// __construct(string $title = '', string $subtitle = '', string $link = '', string $iconUrl = '', string $sinceId = '')
				$item = new WidgetItem($title, $subtitle, $link, self::INLINE_ICON_DATA_URI, $sinceId);

				$items[] = $item;
			}

			// WidgetItems in NC32 supports (array $items, ?string $sinceId)
			return new WidgetItems($items, (string)time());
		} catch (\Throwable $e) {
			$this->logger->error('WikiJsDashboard: getItemsV2 failed: ' . $e->getMessage(), [
				'app' => 'wikijs_dashboard',
				'exception' => $e,
			]);

			// Never break Dashboard: return a single informative item (no link).
			$item = new WidgetItem($this->l10n->t('Dokumentace NPŠ'), $this->l10n->t('Nelze načíst data z Wiki.js (viz nextcloud.log).'), '', self::INLINE_ICON_DATA_URI, (string)time());
			return new WidgetItems([$item], (string)time());
		}
	}

	private function formatUpdatedAt(string $updatedAt): string {
		$updatedAt = trim($updatedAt);
		if ($updatedAt === '') {
			return '';
		}
		try {
			$dt = new \DateTimeImmutable($updatedAt);
			return $dt->format('d.m.Y H:i');
		} catch (\Throwable $e) {
			return $updatedAt;
		}
	}
}
